                       std::same_as<T::value_type, int>;  // ❌ Error: dependent name

// ✅ Fix: Use typename
template<typename T>
concept IntContainer = HasValueType<T> &&
                       std::same_as<typename T::value_type, int>;  // ✅ OK
```

