    }

    // Works with different container types:
    std::array<std::string, 3> words = {"hello", "world", "foo"};
    auto idx2 = find_index(words, std::string("world"));
    if (idx2) {
        std::cout << "Found at index: " << *idx2 << '\n';  // → 1
