Generator<int> map(Generator<int> gen, auto func) {
    for (int val : gen) {
        co_yield func(val);
    }
}

// Lazy take
Generator<int> take(Generator<int> gen, int n) {
    int count = 0;
    for (int val : gen) {
        if (count++ >= n) break;
        co_yield val;
    }
}

