#include <coroutine>
#include <iostream>
#include <queue>
#include <memory>

class Scheduler {
    std::queue<std::coroutine_handle<>> ready_queue_;

public:
    void schedule(std::coroutine_handle<> handle) {
        ready_queue_.push(handle);
    }

    void run() {
        while (!ready_queue_.empty()) {
            auto handle = ready_queue_.front();
            ready_queue_.pop();

            handle.resume();

            if (!handle.done()) {
                ready_queue_.push(handle);  // Re-queue if not done
            }
        }
    }
};

inline Scheduler scheduler;

struct YieldAwaitable {
    bool await_ready() const noexcept { return false; }

    void await_suspend(std::coroutine_handle<> handle) {
        scheduler.schedule(handle);  // Re-schedule this coroutine
    }

    void await_resume() const noexcept {}
};

template<typename T>
struct Task {
    struct promise_type {
        T value_;

        Task get_return_object() {
            return Task{std::coroutine_handle<promise_type>::from_promise(*this)};
        }

        std::suspend_never initial_suspend() { return {}; }  // Start immediately
        std::suspend_always final_suspend() noexcept { return {}; }

        void return_value(T val) {
            value_ = std::move(val);
        }

        void unhandled_exception() {}
    };

    std::coroutine_handle<promise_type> handle_;
};

Task<int> worker(int id) {
    for (int i = 0; i < 3; ++i) {
        std::cout << "Worker " << id << " - iteration " << i << '\n';
        co_await YieldAwaitable{};  // Yield to other tasks
    }
    co_return id;
}

int main() {
    auto task1 = worker(1);
    auto task2 = worker(2);
    auto task3 = worker(3);

    scheduler.run();
}

