    std::exception_ptr exception;

    void unhandled_exception() {
        exception = std::current_exception();  // Store for later
    }
};

void resume() {
    handle.resume();
    if (handle.promise().exception) {
        std::rethrow_exception(handle.promise().exception);  // Propagate to caller
    }
}
```

