#include <bit>
#include <cstdint>
#include <iostream>

enum class Features : uint32_t {
    None         = 0,
    Logging      = 1 << 0,  // Bit 0
    Analytics    = 1 << 1,  // Bit 1
    DarkMode     = 1 << 2,  // Bit 2
    Notifications = 1 << 3,  // Bit 3
    All          = 0xFFFFFFFF
};

class FeatureFlags {
    uint32_t flags_ = 0;

public:
    void enable(Features feature) {
        flags_ |= static_cast<uint32_t>(feature);
    }

    void disable(Features feature) {
        flags_ &= ~static_cast<uint32_t>(feature);
    }

    bool is_enabled(Features feature) const {
