export int subtract(int a, int b) { return a - b; }

// math.h - Header Compatibility (for legacy code)
#ifndef MATH_H
#define MATH_H

#ifdef __cpp_modules
// If modules supported, just import
import math;
#else
// Otherwise, provide traditional declarations
